import { DataRecord, Callback } from './types';

export class DataService {
  private data: DataRecord[] = [];

  getAll(callback: Callback<DataRecord[]>): void {
    try {
      callback(null, [...this.data]);
    } catch (err) {
      callback(err as Error, null);
    }
  }

  getById(id: string, callback: Callback<DataRecord | null>): void {
    try {
      const record = this.data.find(r => r.id === id) || null;
      callback(null, record);
    } catch (err) {
      callback(err as Error, null);
    }
  }

  create(record: Omit<DataRecord, 'id'>, callback: Callback<DataRecord>): void {
    try {
      const newRecord = { ...record, id: String(Date.now()) };
      this.data.push(newRecord);
      callback(null, newRecord);
    } catch (err) {
      callback(err as Error, null);
    }
  }

  delete(id: string, callback: Callback<boolean>): void {
    try {
      const index = this.data.findIndex(r => r.id === id);
      if (index === -1) {
        callback(null, false);
        return;
      }
      this.data.splice(index, 1);
      callback(null, true);
    } catch (err) {
      callback(err as Error, null);
    }
  }
}

