import { DataService } from './service';

const service = new DataService();

export function handleGetAll(req: any, res: any) {
  service.getAll((err, data) => {
    if (err) {
      res.status(500).json({ error: err.message });
      return;
    }
    res.json(data);
  });
}

export function handleGetById(req: any, res: any) {
  service.getById(req.params.id, (err, record) => {
    if (err) {
      res.status(500).json({ error: err.message });
      return;
    }
    if (!record) {
      res.status(404).json({ error: 'Not found' });
      return;
    }
    res.json(record);
  });
}

export function handleCreate(req: any, res: any) {
  service.create(req.body, (err, record) => {
    if (err) {
      res.status(500).json({ error: err.message });
      return;
    }
    res.status(201).json(record);
  });
}

export function handleDelete(req: any, res: any) {
  service.delete(req.params.id, (err, deleted) => {
    if (err) {
      res.status(500).json({ error: err.message });
      return;
    }
    if (!deleted) {
      res.status(404).json({ error: 'Not found' });
      return;
    }
    res.status(204).end();
  });
}

